from qiskit import transpile
from scipy.optimize import minimize

def run_and_analyze(circuit, aer_sim, graph):
    def objective(params):
        gamma_val = params[0]
        beta_val = params[1]
        param_dict = {circuit.parameters[0]: [gamma_val], circuit.parameters[1]: [beta_val]}
        bound_circuit = circuit.assign_parameters({circuit.parameters[0]: gamma_val, circuit.parameters[1]: beta_val})
        transpiled = transpile(bound_circuit, aer_sim)
        result = aer_sim.run(transpiled, shots=10000).result()
        counts = result.get_counts()
        # Reverse bitstrings for compute_expectation
        reversed_counts = {state[::-1]: count for state, count in counts.items()}
        return -compute_expectation(reversed_counts, graph)

    initial_params = [0.5] * circuit.num_parameters
    result = minimize(objective, initial_params, method='COBYLA')

    # Get final counts with optimal parameters
    optimal_params = result.x
    param_dict = {circuit.parameters[0]: optimal_params[0], circuit.parameters[1]: optimal_params[1]}
    bound_circuit = circuit.assign_parameters(param_dict)
    transpiled = transpile(bound_circuit, aer_sim)
    final_result = aer_sim.run(transpiled, shots=10000).result()
    final_counts = final_result.get_counts()

    # Sort by counts
    sorted_counts = sorted(final_counts.items(), key=lambda x: x[1], reverse=True)
    top_two = [state[::-1] for state, count in sorted_counts[:2]]

    return top_two
```

